const BASE_URL = "https://speech-to-text-app-production-9797.up.railway.app";

const getHeaders = (isFormData = false) => {
  const token = localStorage.getItem("token");
  const headers = {};
  if (!isFormData) headers["Content-Type"] = "application/json";
  if (token) headers["Authorization"] = `Bearer ${token}`;
  return headers;
};

const handleResponse = async (res) => {
  const contentType = res.headers.get("content-type") || "";
  const isJson = contentType.includes("application/json");

  const safeJson = async () => {
    // Some backends return 204/empty body; res.json() would throw "unexpected end of JSON".
    const text = await res.text();
    if (!text) return {};
    try {
      return JSON.parse(text);
    } catch {
      return {};
    }
  };

  const safeText = async () => {
    try {
      return await res.text();
    } catch {
      return "";
    }
  };

  if (!res.ok) {
    if (isJson) {
      const err = await safeJson();
      throw new Error(err.message || `HTTP ${res.status}`);
    }
    const msg = await safeText();
    throw new Error(msg || `HTTP ${res.status}`);
  }

  if (!isJson) {
    // For endpoints that return no JSON (or empty body), return empty object.
    await safeText();
    return {};
  }

  return safeJson();
};

// Auth
export const register = (data) =>
  fetch(`${BASE_URL}/api/auth/register`, {
    method: "POST",
    headers: getHeaders(),
    body: JSON.stringify(data),
  }).then(handleResponse);

export const login = (data) =>
  fetch(`${BASE_URL}/api/auth/login`, {
    method: "POST",
    headers: getHeaders(),
    body: JSON.stringify(data),
  }).then(handleResponse);

// Speech
export const uploadAudio = (formData) =>
  fetch(`${BASE_URL}/api/speech/upload`, {
    method: "POST",
    headers: getHeaders(true),
    body: formData,
  }).then(handleResponse);

export const transcribeAudio = (formData) =>
  fetch(`${BASE_URL}/api/speech/transcribe`, {
    method: "POST",
    headers: getHeaders(true),
    body: formData,
  }).then(handleResponse);

export const getHistory = () =>
  fetch(`${BASE_URL}/api/speech/history`, {
    headers: getHeaders(),
  }).then(handleResponse);

export const getTranscript = (id) =>
  fetch(`${BASE_URL}/api/speech/${id}`, {
    headers: getHeaders(),
  }).then(handleResponse);
